// Unit 9. Vrije Tijd & Plannen
// Future, Subordinate Clauses & Hobbies

export default {n:9,lang:"nl",srcLang:"en",track:"v2",title:"Vrije Tijd & Plannen",sub:"Future, Subordinate Clauses & Hobbies",icon:"⚽",level:"A2.1",color:"#7B5EE8",lessons:[
  {id:"v2u9l1",title:"Wat Doe Je Graag?",icon:"🎨",xp:15,board:true,steps:[
        {type:"intro",title:"Wat Doe Je Graag?",desc:"Before making plans, you need hobbies. Dutch uses 'graag' (gladly) where English uses 'like to': 'Ik zwem graag' = I like to swim. This lesson teaches hobby/leisure vocabulary and the graag construction.",goals:["8 hobby/leisure words","'Graag' for expressing likes","'Liever' for preferences","Talk about what you enjoy"]},
        {type:"teach",trg:"zwemmen",src:"to swim",pos:"verb",gender:null,phonetic:"ZVEM-mun",note:"Regular verb. Stam = zwem.\n'Graag' goes after the verb for 'like to':\nIk zwem graag = I gladly swim = I like swimming.",example:"A: Ik zwem graag.\nB: Veel plezier!\nA: Goed punt.",exampleSrc:"A: I like to swim.\nB: Have fun!\nA: Good point.",funFact:"Germanic cousin of English 'swim', German 'schwimmen'."},
        {type:"teach",trg:"lezen",src:"to read",pos:"verb",gender:null,phonetic:"LAY-zun",note:"Irregular in past tense (gelezen), but regular in present.\nStam = lees. zij leest (stam + t).",example:"A: Zij leest graag boeken.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: She likes reading books.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Germanic cousin of German 'lesen'."},
        {type:"teach",trg:"koken",src:"to cook",pos:"verb",gender:null,phonetic:"KOH-kun",note:"Regular. Stam = kook.\nYou already know this from Unit 4!",example:"A: Wij koken graag samen.\nB: O, dat wist ik niet.\nA: Nu wel!",exampleSrc:"A: We like cooking together.\nB: Oh, I didn't know that.\nA: Now you do!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"wandelen",src:"to walk / to hike",pos:"verb",gender:null,phonetic:"VAN-duh-lun",note:"The 'recreational walk' verb from Unit 7.\n'Het bos' = the forest. Popular Dutch weekend activity.",example:"A: Ik wandel graag in het bos.\nB: Dat klinkt leuk! Mag ik mee?\nA: Inderdaad.",exampleSrc:"A: I like walking in the forest.\nB: That sounds fun! Can I come along?\nA: Indeed.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"sporten",src:"to exercise / to do sports",pos:"verb",gender:null,phonetic:"SPOR-tun",note:"Verb form of 'sport'. Very common.\n'Sporten' covers gym, running, cycling, etc.\nThe Dutch are among Europe's most active people.",example:"A: Hij sport drie keer per week.\nB: Hoe laat precies?\nA: Klopt!",exampleSrc:"A: He exercises three times a week.\nB: What time exactly?\nA: Right!",funFact:"international cousin of English 'sport', German 'Sport treiben'."},
        {type:"teach",trg:"het bos",src:"the forest",pos:"noun",gender:"n",phonetic:"hut bos",note:"Het-word. The Netherlands has more forests than you'd think.\nVeluwe, Utrechtse Heuvelrug, Hoge Veluwe national park.",example:"A: Wij wandelen in het bos.\nB: Dat klinkt leuk! Mag ik mee?\nA: Ja, precies!",exampleSrc:"A: We walk in the forest.\nB: That sounds fun! Can I come along?\nA: Yes, exactly!",funFact:"Germanic cousin of English 'bush', German 'Busch'."},
        {type:"tip",title:"📐 Graag vs Liever vs Het Liefst",text:"GRAAG = gladly (= like to)\nIk zwem graag. = I like swimming.\n\nLIEVER = rather (= prefer to)\nIk fiets liever. = I prefer cycling.\n\nHET LIEFST = most of all (= like most)\nIk wandel het liefst. = I like walking most of all.\n\nThis is a comparative system:\ngraag → liever → het liefst\n(gladly → rather → most gladly)\n\nExample conversation:\nWat doe je graag? = What do you like doing?\nIk zwem graag, maar ik fiets liever.\n= I like swimming, but I prefer cycling.\nIk wandel het liefst.\n= What I like most is walking."},
        {type:"mc",q:"'Ik zwem graag' means:",opts:["I like swimming","I swim fast","I swim rarely","I can swim"],ans:"I like swimming",hint:"graag = gladly = l... to"},
        {type:"fb",opts:["liever","graag","het liefst","meer"],hint:"I PREFER cycling to walking",s:"Ik fiets ___ dan wandelen.",a:"liever"},
        {type:"match",pairs:[{trg:"zwemmen",src:"to swim"},{trg:"lezen",src:"to read"},{trg:"wandelen",src:"to walk/hike"},{trg:"sporten",src:"to exercise"}]},
        {type:"drag_fill",hint:"Express what you enjoy, then contrast with what you prefer",s:"Ik zwem {1}, maar ik wandel {2}.",blanks:{"1":"graag","2":"liever"},pool:["graag","liever","het liefst","minder"]},
        {type:"mc",q:"'Het liefst' is the ___ of 'graag':",opts:["comparative","superlative","imperative","infinitive"],ans:"superlative",hint:"Comparative of the adverb meaning 'gladly/with pleasure'"},
        {type:"fb",opts:["graag","liever","niet","altijd"],hint:"What do you GLADLY do?",s:"Wat doe je ___? (= What do you like doing?)",a:"graag"}
  ]},
  {id:"v2u9l2",title:"Ik Ga Zwemmen",icon:"🏊",xp:20,board:true,steps:[
        {type:"intro",title:"Ik Ga Zwemmen",desc:"Dutch uses 'gaan + infinitive' for the near future  -  identical to English 'I'm going to swim.' This is the most common way to talk about plans in Dutch. Simple, natural, and you already know 'gaan'.",goals:["gaan + infinitive for future plans","Time expressions for the future","Make and discuss plans","Difference from 'zullen'"]},
        {type:"teach",trg:"ik ga zwemmen",src:"I'm going to swim",pos:"verb",gender:null,phonetic:"ik gah ZVEM-mun",note:"COMPOUND: gaan + infinitive.\ngaan + infinitive = going to [verb].\nExact same structure as English!\nThe infinitive goes to the END (like modals).",example:"A: Ik ga morgen zwemmen.\nB: Hoe laat precies?\nA: Klopt!",exampleSrc:"A: I'm going to swim tomorrow.\nB: What time exactly?\nA: Right!",funFact:"Dutch compounds are transparent once you learn the parts."},
        {type:"teach",trg:"volgende week",src:"next week",pos:"noun",gender:"n",phonetic:"VOL-gun-duh vayk",note:"volgende = next/following.\nVolgende week, volgende maand, volgend jaar.\nNote: 'volgend jaar' (het-word → no -e).",example:"A: Volgende week ga ik op vakantie.\nB: O, is het al zo laat?\nA: Goed punt.",exampleSrc:"A: Next week I'm going on holiday.\nB: Oh, is it that late already?\nA: Good point.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"binnenkort",src:"soon",pos:"noun",gender:null,phonetic:"BIN-nun-kort",note:"COMPOUND: binnen + kort.\nbinnen + kort = within + short.\nLiterally: 'within a short time'.\n'Binnenkort' = soon but not immediate.",example:"A: Ik ga binnenkort naar de dokter.\nB: Gaat het goed met je?\nA: Dat is zo.",exampleSrc:"A: I'm going to the doctor soon.\nB: Are you doing okay?\nA: That's true.",funFact:"Dutch compounds are transparent once you learn the parts."},
        {type:"teach",trg:"op vakantie",src:"on holiday / on vacation",pos:"intj",gender:null,phonetic:"op vah-KAN-see",note:"'Op vakantie gaan' = to go on holiday.\nThe Dutch LOVE holidays. Average: 25 vacation days/year.\n'Waar ga je op vakantie?' = Where are you going on holiday?",example:"A: Wij gaan volgende week op vakantie.\nB: O, is het al zo laat?\nA: Goed punt.",exampleSrc:"A: We're going on holiday next week.\nB: Oh, is it that late already?\nA: Good point.",funFact:"international cousin of French 'vacances', German 'Vakanz (rare)'."},
        {type:"teach",trg:"samen",src:"together",pos:"verb",gender:null,phonetic:"SAH-mun",note:"Very common word.\n'Samen' makes everything warmer.\n'Zullen we samen gaan?' = Shall we go together?",example:"A: Wij gaan samen eten.\nB: Mmm, dat klinkt lekker!\nA: Dat is zo.",exampleSrc:"A: We're going to eat together.\nB: Mmm, that sounds delicious!\nA: That's true.",funFact:"Germanic cousin of English 'same', German 'zusammen'."},
        {type:"tip",title:"📐 Future with 'gaan'",text:"Subject + gaan + ... + infinitive (at end)\n\nIk ga morgen zwemmen. = I'm going to swim tomorrow.\nWij gaan volgende week op vakantie.\n= We're going on holiday next week.\nZij gaat vanavond koken.\n= She's going to cook tonight.\n\nThis is the casual/spoken future.\nDutch also has 'zullen' (shall/will)  -  next lesson.\nBut 'gaan + infinitive' covers 90% of future plans.\n\nNegation: Ik ga morgen niet zwemmen.\n= I'm not going to swim tomorrow.\n'Niet' goes before the infinitive.\n\nQuestion: Ga je morgen zwemmen?\n= Are you going to swim tomorrow?"},
        {type:"mc",q:"'Ik ga morgen zwemmen' is:",opts:["future (with gaan + infinitive)","present tense","past tense","imperative"],ans:"future (with gaan + infinitive)",hint:"Going to = ___ plans"},
        {type:"fb",opts:["gaan","ga","gaat","gegaan"],hint:"Wij takes the full infinitive form, not the -t form",s:"Wij ___ volgende week op vakantie.",a:"gaan"},
        {type:"match",pairs:[{trg:"volgende week",src:"next week"},{trg:"binnenkort",src:"soon"},{trg:"op vakantie",src:"on holiday"},{trg:"samen",src:"together"}]},
        {type:"drag_fill",hint:"She IS GOING TO cook tonight.",s:"Zij {1} vanavond {2}.",blanks:{"1":"gaat","2":"koken"},pool:["gaat","koken","ga","gekookt"]},
        {type:"fb",opts:["Ga","Gaat","Gaan","Ging"],hint:"Are you going to swim? (question: -t drops)",s:"___ je morgen zwemmen?",a:"Ga"},
        {type:"mc",q:"The infinitive in 'gaan + infinitive' goes:",opts:["before gaan","at the end","after the subject","anywhere"],ans:"at the end",hint:"Same rule as modals and perfect tense"},
        {type:"tr",mk:"u9v2_going_swimming",dir:"produce"}
  ]},
  {id:"v2u9l3",title:"Zal Ik...?",icon:"💬",xp:15,board:true,steps:[
        {type:"intro",title:"Zal Ik...?",desc:"The second future construction: 'zullen' (shall/will). Less common than 'gaan' for plans, but essential for offers ('Shall I help?'), promises ('I will do it'), and predictions. Plus: making suggestions in Dutch.",goals:["Conjugate zullen","Offers with 'zal ik'","Promises with 'ik zal'","Zullen vs gaan: when to use which"]},
        {type:"teach",trg:"zullen",src:"shall / will",pos:"verb",gender:null,phonetic:"ZUL-lun",note:"Modal-like verb. Same word order.\nik zal, jij zult/zal, hij zal, wij zullen.\nMore formal/distant than 'gaan'.",example:"A: Zal ik je helpen?\nB: Ik hoop dat je je snel beter voelt!\nA: Dat is zo.",exampleSrc:"A: Shall I help you?\nB: I hope you feel better soon!\nA: That's true.",funFact:"Germanic cousin of English 'shall', German 'sollen'."},
        {type:"teach",trg:"zal ik",src:"shall I",pos:"verb",gender:null,phonetic:"zal ik",note:"THE offer construction.\n'Zal ik [infinitive]?' = Shall I [verb]?\nVery polite and helpful-sounding.",example:"A: Zal ik koffie maken?\nB: Mmm, dat klinkt lekker!\nA: Klopt!",exampleSrc:"A: Shall I make coffee?\nB: Mmm, that sounds delicious!\nA: Right!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"ik zal",src:"I will / I shall",pos:"verb",gender:null,phonetic:"ik zal",note:"Promise/intention.\n'Ik zal het niet vergeten.' = I won't forget it.\nMore formal than 'ik ga het doen'.",example:"A: Ik zal het doen.\nB: Dat klopt.\nA: Precies!",exampleSrc:"A: I will do it.\nB: That's right.\nA: Exactly!",funFact:"ik + zal: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"helpen",src:"to help",pos:"verb",gender:null,phonetic:"HEL-pun",note:"Regular in present. Irregular past: geholpen.\nIdentical to English. 'Help!' = 'Help!'",example:"A: Kan ik je helpen?\nB: Misschien moet je naar de dokter.\nA: Ja, precies!",exampleSrc:"A: Can I help you?\nB: Maybe you should see a doctor.\nA: Yes, exactly!",funFact:"Germanic cousin of English 'help', German 'helfen'."},
        {type:"teach",trg:"vergeten",src:"to forget",pos:"verb",gender:null,phonetic:"fur-GAY-tun",note:"ver- prefix → no ge- in past participle: vergeten.\nThe past participle is the same as the infinitive!\nvergeten → vergeten. (Like English: forget → forgotten)",example:"A: Ik zal het niet vergeten.\nB: Mmm, dat klinkt lekker!\nA: Dat is zo.",exampleSrc:"A: I won't forget it.\nB: Mmm, that sounds delicious!\nA: That's true.",funFact:"Germanic cousin of English 'forget', German 'vergessen'."},
        {type:"tip",title:"⚖️ Gaan vs Zullen",text:"GAAN = concrete plans (going to)\nIk ga morgen zwemmen. = I'm going to swim tomorrow.\n(You've decided. It's planned.)\n\nZULLEN = offers, promises, predictions\nZal ik helpen? = Shall I help? (offer)\nIk zal het doen. = I will do it. (promise)\nHet zal morgen regenen. = It will rain tomorrow. (prediction)\n\nIn practice:\n'Gaan' covers 90% of future talk.\n'Zullen' is for offers ('Zal ik...?') and promises.\n\nDutch people rarely say 'ik zal morgen zwemmen.'\nThey say 'ik ga morgen zwemmen.'\n'Zullen' sounds more formal/distant for plans."},
        {type:"mc",q:"'Zal ik koffie maken?' is:",opts:["an offer","a command","a complaint","a past action"],ans:"an offer",hint:"Shall I...? = ___ing to do something"},
        {type:"fb",opts:["zal","ga","heb","ben"],hint:"I WILL not forget = promise",s:"Ik ___ het niet vergeten.",a:"zal"},
        {type:"match",pairs:[{trg:"zal ik helpen?",src:"shall I help?"},{trg:"ik ga zwemmen",src:"I'm going to swim"},{trg:"ik zal het doen",src:"I will do it"},{trg:"vergeten",src:"to forget"}]},
        {type:"mc",q:"For concrete plans, Dutch prefers:",opts:["zullen","gaan","moeten","kunnen"],ans:"gaan",hint:"Ik GA morgen zwemmen (not zal)"},
        {type:"drag_fill",hint:"Shall I help? (offer) I'm going to swim. (plan)",s:"{1} ik je helpen? Ik {2} morgen zwemmen.",blanks:{"1":"Zal","2":"ga"},pool:["Zal","ga","Moet","kan"]},
        {type:"fb",opts:["Zal","Ga","Moet","Kan"],hint:"Shall I...? (offering)",s:"___ ik koffie maken?",a:"Zal"},
        {type:"tr",mk:"u9v2_shall_i_help",dir:"produce"}
  ]},
  {id:"v2u9l4",title:"Omdat Het Leuk Is",icon:"📎",xp:20,board:true,steps:[
        {type:"intro",title:"Omdat Het Leuk Is",desc:"The hardest word-order rule in Dutch: subordinate clauses. Since Unit 3 you've been using V2  -  the verb always in position 2. Now meet V-FINAL: when you use 'omdat' (because), 'dat' (that), or 'als' (if/when), the verb goes to the END. This is the #1 error even at B1 level. We're tackling it head-on.",goals:["Subordinate clause word order","omdat (because), dat (that), als (if/when)","Verb-final in subordinate clauses","Why this exists and how to practice"]},
        {type:"tip",title:"🔑 The Verb Goes to the End",text:"Remember the V2 rule from Unit 3?\nIn main clauses, the verb is ALWAYS in position 2:\nIk drink koffie. = I drink coffee.\nSoms drink ik koffie. = Sometimes I drink coffee.\n\nSubordinate clauses break this rule.\nThe verb moves to the VERY END:\n...omdat ik koffie DRINK. = ...because I drink coffee.\n\nMain: Het is leuk.\nSubordinate: ...omdat het leuk IS.\n\nMain: Ik kan niet komen.\nSubordinate: ...omdat ik niet kan KOMEN.\n       (OR: ...omdat ik niet KAN komen.)\n\nTrigger words (conjunctions):\nomdat = because\ndat = that\nals = if / when\nwanneer = when\nterwijl = while\nhoewel = although\n\nAfter ANY of these, the conjugated verb moves to the end.\nThis is the #1 Dutch word order rule and the #1 error.\nPractice it until it becomes automatic."},
        {type:"teach",trg:"omdat",src:"because",pos:"verb",gender:null,phonetic:"om-DAT",note:"The most common subordinating conjunction.\nAfter 'omdat': VERB TO THE END.\n...omdat ik in Amsterdam WOON.\nNot: ...omdat ik woon in Amsterdam.",example:"A: Ik leer Nederlands omdat ik in Amsterdam woon.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: I'm learning Dutch because I live in Amsterdam.\nB: That's good to know.\nA: Yes, for sure!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"dat",src:"that",pos:"verb",gender:null,phonetic:"dat",note:"'That' as conjunction (not demonstrative).\nAfter 'dat': verb to the end.\n...dat hij ziek IS.\nNot: ...dat hij is ziek.",example:"A: Ik denk dat hij ziek is.\nB: Gaat het goed met je?\nA: Goed punt.",exampleSrc:"A: I think that he is sick.\nB: Are you doing okay?\nA: Good point.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"als",src:"if / when",pos:"verb",gender:null,phonetic:"als",note:"Two meanings: 'if' and 'when' (conditions).\nAfter 'als': verb to the end.\n...als het REGENT...\nNot: ...als regent het...",example:"A: Als het regent, blijf ik thuis.\nB: Is het een groot huis?\nA: Ja, precies!",exampleSrc:"A: If it rains, I stay home.\nB: Is it a big house?\nA: Yes, exactly!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"denken",src:"to think",pos:"verb",gender:null,phonetic:"DENG-kun",note:"Regular verb. Stam = denk.\nOften followed by 'dat': 'Ik denk dat...'",example:"A: Ik denk dat het gaat regenen.\nB: Ik hoop dat het beter wordt.\nA: Klopt!",exampleSrc:"A: I think that it's going to rain.\nB: I hope it gets better.\nA: Right!",funFact:"Germanic cousin of English 'think', German 'denken'."},
        {type:"teach",trg:"weten",src:"to know (a fact)",pos:"verb",gender:null,phonetic:"VAY-tun",note:"Irregular: ik weet, jij weet, wij weten.\nDistinct from 'kennen' (to know a person).\n'Ik weet het niet.' = I don't know.\nEnglish 'wit' used to mean 'to know'  -  as in\n'to wit' (= namely), 'witness' (one who knows),\nand 'witty' (originally: knowledgeable, clever).\nDutch kept 'weten' as the everyday word for knowing facts.",example:"A: Ik weet dat hij in Rotterdam woont.\nB: Mmm, dat klinkt lekker!\nA: Dat is zo.",exampleSrc:"A: I know that he lives in Rotterdam.\nB: Mmm, that sounds delicious!\nA: That's true.",funFact:"Germanic cousin of English 'wit (Old English: to know)', German 'wissen'."},
        {type:"teach",trg:"dus",src:"so / therefore",pos:"verb",gender:null,phonetic:"dus",note:"Coordinating conjunction  -  NORMAL word order.\nCompare:\nomdat → verb goes to END: ...omdat het regent.\ndus → verb stays in position 2: ...dus ik blijf thuis.\n\n'Dus' is English 'thus'  -  same Germanic root.",example:"A: Het regent, dus ik blijf thuis.\nB: Wat een mooi huis!\nA: Dat is zo.",exampleSrc:"A: It's raining, so I stay home.\nB: What a nice house!\nA: That's true.",funFact:"Germanic cousin of English 'thus', German 'also (thus)'."},
        {type:"tip",title:"⚠️ With Modal Verbs",text:"When a subordinate clause has a modal verb,\nBOTH verbs go to the end:\n\nMain: Ik kan niet komen.\nSubordinate: ...omdat ik niet kan komen.\n             OR: ...omdat ik niet komen kan.\n\nBoth orders are accepted in modern Dutch.\nThe most natural: modal + infinitive at the end.\n\n...omdat ik niet KAN KOMEN.\n...dat ik morgen MOET WERKEN.\n...als ik niet KAN ZWEMMEN.\n\nWith perfect tense:\n...omdat ik heb GEWERKT.\nOR: ...omdat ik GEWERKT heb.\n\nAgain, both are fine. Don't overthink it.\nJust get the verb(s) to the end."},
        {type:"mc",q:"'...omdat ik in Amsterdam woon.'  -  the verb is at the END because:",opts:["'omdat' triggers verb-final order","It's a question","The sentence is negative","It's always like this"],ans:"'omdat' triggers verb-final order",hint:"Subordinating conjunctions → ___ to end"},
        {type:"fb",opts:["woon","woont","wonen","gewoond"],hint:"...because I LIVE in the Netherlands (verb at end)",s:"Ik leer Nederlands omdat ik in Nederland ___.",a:"woon"},
        {type:"mc",q:"'Ik denk dat hij ziek ___.'",opts:["ben","is","zijn","was"],ans:"is",hint:"dat hij ziek IS  -  verb at end"},
        {type:"match",pairs:[{trg:"omdat",src:"because"},{trg:"dat",src:"that"},{trg:"als",src:"if / when"},{trg:"wanneer",src:"when"}]},
        {type:"drag_fill",hint:"...because it rains. ...that he sick IS.",s:"Ik blijf thuis omdat het {1}. Ik denk dat hij {2} is.",blanks:{"1":"regent","2":"ziek"},pool:["regent","ziek","regenen","is"]},
        {type:"fb",opts:["is","ben","zijn","was"],hint:"If the weather nice IS... (verb at end in als-clause)",s:"Als het mooi weer ___, ga ik fietsen.",a:"is"},
        {type:"mc",q:"In subordinate clauses, Dutch word order becomes:",opts:["V1 (verb first)","V2 (verb second)","V-final (verb at end)","V-free (anywhere)"],ans:"V-final (verb at end)",hint:"Main clause = V2. Subordinate = V-___."},
        {type:"fb",opts:["woont","woon","wonen","gewoond"],hint:"...that he in Rotterdam LIVES (verb at end, hij = -t)",s:"Ik weet dat hij in Rotterdam ___.",a:"woont"},
        {type:"tr",mk:"u9v2_because_fun",dir:"produce"}
  ]},
  {id:"v2u9l5",title:"Als Het Mooi Weer Is...",icon:"🌤️",xp:15,board:true,steps:[
        {type:"intro",title:"Als Het Mooi Weer Is...",desc:"Practice subordinate clauses with 'als' (if/when) in real scenarios: weather, plans, conditions. Also introduces 'wanneer' (when) and the important structure where the subordinate clause comes FIRST.",goals:["'Als' for conditions and hypotheticals","Subordinate clause FIRST → inverted main clause","Weather vocabulary","Make conditional plans"]},
        {type:"teach",trg:"het weer",src:"the weather",pos:"noun",gender:"n",phonetic:"hut vayr",note:"Het-word. THE Dutch small-talk topic.\nThe Netherlands has unpredictable weather.\n'Lekker weer!' = Nice weather!",example:"A: Het weer is mooi vandaag.\nB: Ik hoop dat het beter wordt.\nA: Goed punt.",exampleSrc:"A: The weather is nice today.\nB: I hope it gets better.\nA: Good point.",funFact:"Germanic cousin of English 'weather', German 'Wetter'."},
        {type:"teach",trg:"regenen",src:"to rain",pos:"verb",gender:null,phonetic:"RAY-guh-nun",note:"'Het regent' = it rains. Impersonal verb.\nRain is the defining Dutch weather experience.\n'Wij fietsen in de regen.' = We cycle in the rain.",example:"A: Het regent vaak in Nederland.\nB: Ik hoop dat het beter wordt.\nA: Goed punt.",exampleSrc:"A: It rains often in the Netherlands.\nB: I hope it gets better.\nA: Good point.",funFact:"Germanic cousin of English 'rain', German 'regnen'."},
        {type:"teach",trg:"de regen",src:"the rain",pos:"noun",gender:"c",phonetic:"duh RAY-gun",note:"De-word. 'In de regen' = in the rain.\nThe Dutch don't cancel plans because of rain.\nThey just cycle faster.",example:"A: Ik fiets door de regen.\nB: Goede reis!\nA: Dat is zo.",exampleSrc:"A: I cycle through the rain.\nB: Have a good trip!\nA: That's true.",funFact:"Germanic cousin of English 'rain', German 'Regen'."},
        {type:"teach",trg:"de zon",src:"the sun",pos:"noun",gender:"c",phonetic:"duh zon",note:"De-word. 'De zon schijnt' = the sun shines.\nWhen the sun appears in NL, everything stops.\nTerraces fill. Parks fill. Life moves outside.",example:"A: De zon schijnt!\nB: Ik hoop dat het beter wordt.\nA: Goed punt.",exampleSrc:"A: The sun is shining!\nB: I hope it gets better.\nA: Good point.",funFact:"Germanic cousin of English 'sun', German 'Sonne'."},
        {type:"teach",trg:"wanneer",src:"when (in time)",pos:"verb",gender:null,phonetic:"van-NAYR",note:"'Wanneer' = when (subordinating conjunction).\nSame verb-final rule as 'als'.\nSubtle difference: wanneer = more specific time.",example:"A: Wanneer het zomer is, ga ik zwemmen.\nB: Dat weet ik ook niet zeker.\nA: Goed punt.",exampleSrc:"A: When it's summer, I go swimming.\nB: I'm not sure about that either.\nA: Good point.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"tip",title:"📐 Subordinate Clause First",text:"When the subordinate clause comes FIRST,\nthe main clause starts with the verb (inversion):\n\nNormal: Ik ga fietsen als het mooi weer is.\n= I'm going cycling if the weather is nice.\n\nReversed: Als het mooi weer is, ga ik fietsen.\n= If the weather is nice, I'm going cycling.\n\nThe comma separates the clauses.\nAfter the comma: VERB first, then subject.\n\nMore examples:\nOmdat het regent, blijf ik thuis.\n= Because it's raining, I stay home.\n\nAls ik tijd heb, ga ik wandelen.\n= If I have time, I'll go walking.\n\nThis looks complex but the rule is simple:\nSubordinate clause = verb at end.\nMain clause after subordinate = verb first."},
        {type:"mc",q:"'Als het regent, blijf ik thuis.'  -  why 'blijf' before 'ik'?",opts:["The subordinate clause came first → main clause inverts","It's a question","It's wrong","There's no rule"],ans:"The subordinate clause came first → main clause inverts",hint:"___ ___ → verb-subject in ___ ___"},
        {type:"fb",opts:["is","ben","zijn","was"],hint:"If the weather nice IS (verb at end)",s:"Als het mooi weer ___, ga ik fietsen.",a:"is"},
        {type:"match",pairs:[{trg:"het weer",src:"the weather"},{trg:"regenen",src:"to rain"},{trg:"de zon",src:"the sun"},{trg:"wanneer",src:"when"}]},
        {type:"drag_fill",hint:"If it rains... If the sun shines...",s:"Als het {1}, blijf ik thuis. Als de zon {2}, ga ik fietsen.",blanks:{"1":"regent","2":"schijnt"},pool:["regent","schijnt","regen","zon"]},
        {type:"fb",opts:["Als","Omdat","Dat","Maar"],hint:"IF I have time...",s:"___ ik tijd heb, ga ik wandelen.",a:"Als"},
        {type:"mc",q:"The Dutch attitude to rain is:",opts:["Stay inside","Cycle faster and keep going","Cancel plans","Complain and do nothing"],ans:"Cycle faster and keep going",hint:"Rain doesn't stop the Dutch!"},
        {type:"tr",mk:"u9v2_if_nice_weather",dir:"produce"}
  ]},
  {id:"v2u9l6",title:"Om Te...",icon:"🎯",xp:15,board:true,steps:[
        {type:"intro",title:"Om Te...",desc:"'Om... te...' = 'in order to.' A purpose clause that sends the infinitive to the end. 'Ik leer Nederlands om in Amsterdam te werken.' Clean, elegant, and very common in Dutch daily speech.",goals:["The 'om... te...' construction","Express purpose and goals","Combine with other subordinate clauses","Natural conversation examples"]},
        {type:"teach",trg:"om... te...",src:"in order to...",pos:"verb",gender:null,phonetic:"om ... tuh",note:"'Om' starts the purpose clause.\n'Te' goes right before the infinitive.\nThe infinitive is at the END.\nom [middle stuff] te [infinitive].",example:"A: Ik leer Nederlands om in Amsterdam te werken.\nB: Dat klinkt als een goede baan.\nA: Klopt!",exampleSrc:"A: I'm learning Dutch in order to work in Amsterdam.\nB: That sounds like a good job.\nA: Right!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"nodig",src:"necessary / needed",pos:"adj",gender:null,phonetic:"NOH-dug",note:"Adjective. 'Nodig hebben' = to need.\n'Ik heb een pen nodig.' = I need a pen.\n'Het is nodig om...' = It is necessary to...",example:"A: Het is niet nodig om te betalen.\nB: Zal ik betalen?\nA: Dat is zo.",exampleSrc:"A: It's not necessary to pay.\nB: Shall I pay?\nA: That's true.",funFact:"Dutch adjectives add -e before de-words but stay bare before het-words: 'de grote man' vs 'het groot huis'."},
        {type:"teach",trg:"proberen",src:"to try",pos:"verb",gender:null,phonetic:"proh-BAY-run",note:"Regular verb. Stam = probeer.\n'Proberen om... te...' = try to...\n'Probeer het maar!' = Just try it!",example:"A: Ik probeer om Nederlands te spreken.\nB: Wanneer ga je?\nA: Inderdaad.",exampleSrc:"A: I try to speak Dutch.\nB: When are you going?\nA: Indeed.",funFact:"international cousin of German 'probieren', French 'essayer (different)'."},
        {type:"tip",title:"📐 Om Te in Practice",text:"Purpose:\nIk leer Nederlands om in Amsterdam te werken.\n= I'm learning Dutch in order to work in Amsterdam.\n\nIk fiets om gezond te blijven.\n= I cycle in order to stay healthy.\n\nWith separable verbs (ge-/prefix goes back together):\nIk bel om een afspraak te maken.\n= I'm calling to make an appointment.\n(NOT: om een afspraak te 'maak')\n\nAfter certain verbs:\nIk probeer om op tijd te komen.\n= I try to come on time.\n\nHij vergeet om te betalen.\n= He forgets to pay.\n\nNote: some verbs use 'te' without 'om':\nIk probeer te slapen. = I try to sleep.\nBut with 'om' is also correct and very common."},
        {type:"mc",q:"'Ik leer Nederlands om in Amsterdam te werken.'  -  'om...te' expresses:",opts:["purpose","cause","time","location"],ans:"purpose",hint:"Om...te expresses WHY you do something"},
        {type:"fb",opts:["om","dat","als","omdat"],hint:"I cycle IN ORDER TO stay healthy",s:"Ik fiets ___ gezond te blijven.",a:"om"},
        {type:"match",pairs:[{trg:"om...te...",src:"in order to"},{trg:"nodig",src:"necessary"},{trg:"proberen",src:"to try"}]},
        {type:"drag_fill",hint:"I learn Dutch IN ORDER TO work in Amsterdam.",s:"Ik leer Nederlands {1} in Amsterdam te {2}.",blanks:{"1":"om","2":"werken"},pool:["om","werken","dat","gewerkt"]},
        {type:"fb",opts:["probeer","proberen","probeerde","geprobeerd"],hint:"I TRY to speak Dutch (ik = stam)",s:"Ik ___ om Nederlands te spreken.",a:"probeer"},
        {type:"mc",q:"In 'om... te...', the infinitive goes:",opts:["at the start","right after te (at the end)","after om","before om"],ans:"right after te (at the end)",hint:"om [stuff] te [infinitive]"},
        {type:"tr",mk:"u9v2_in_order_to",dir:"produce"}
  ]},
  {id:"v2u9l7",title:"Koningsdag!",icon:"👑",xp:15,board:true,steps:[
        {type:"intro",title:"Koningsdag!",desc:"April 27: the entire Netherlands turns orange. Koningsdag (King's Day) is the biggest national celebration  -  bigger than Christmas, bigger than New Year. Free markets, live music, boats, beer, and national pride. This is where language meets culture at full volume.",goals:["Koningsdag vocabulary","Dutch national celebrations","Practice all Unit 9 grammar in context","Cultural deep dive: oranje gekte"]},
        {type:"tip",title:"🇳🇱 Koningsdag: April 27",text:"Koningsdag (King's Day) = King Willem-Alexander's birthday.\n\nThe rules:\n• Wear orange. Everything orange. No exceptions.\n• The whole country becomes a vrijmarkt (free market).\n  Anyone can sell anything on the street. No permits needed.\n• Live music on every corner.\n• Amsterdam's canals fill with boats blasting music.\n• Beer. Lots of beer. Starting at 8 AM.\n\n'Oranje gekte' = orange madness.\n\nKoningsnacht (King's Night, April 26) is when it starts.\nBy noon on April 27, every street is packed.\n\nThe color orange? From the House of Orange-Nassau,\nthe Dutch royal family. William of Orange (1533–1584)\nled the Dutch revolt against Spain.\n\n'Lang leve de Koning!' = Long live the King!\n'Oranje boven!' = Orange on top! (national cheer)"},
        {type:"teach",trg:"de koning",src:"the king",pos:"noun",gender:"c",phonetic:"duh KOH-ning",note:"De-word. Current king: Willem-Alexander (since 2013).\nThe Dutch monarchy is very popular.\nThe royal family is seen as 'normaal'  -  the ultimate Dutch compliment.",example:"A: De koning woont in Den Haag.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: The king lives in The Hague.\nB: That's good to know.\nA: Yes, for sure!",funFact:"Germanic cousin of English 'king', German 'König'."},
        {type:"teach",trg:"vieren",src:"to celebrate",pos:"verb",gender:null,phonetic:"VEE-run",note:"Regular verb. Stam = vier.\n'Vieren' works for all celebrations:\nverjaardag vieren, Koningsdag vieren.",example:"A: Wij gaan Koningsdag vieren!\nB: Hoe gaat het met je?\nA: Inderdaad.",exampleSrc:"A: We're going to celebrate King's Day!\nB: How are you?\nA: Indeed.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"oranje",src:"orange (color)",pos:"noun",gender:null,phonetic:"oh-RAN-yuh",note:"Both the color and the national symbol.\n'Oranje' = the royal House of Orange.\nOn Koningsdag: orange clothes, orange food, orange everything.",example:"A: Iedereen draagt oranje!\nB: Wat leuk!\nA: Ja, inderdaad!",exampleSrc:"A: Everyone wears orange!\nB: How nice!\nA: Yes, indeed!",funFact:"international cousin of English 'orange', French 'orange'."},
        {type:"teach",trg:"het feest",src:"the party / celebration",pos:"verb",gender:null,phonetic:"hut fayst",note:"Het-word. 'Een feestje' = a little party (diminutive).\n'Feesten' = to party (verb). Cognate of English 'feast'.",example:"A: Koningsdag is het grootste feest van het jaar.\nB: Ja, tot de volgende keer!\nA: Klopt!",exampleSrc:"A: King's Day is the biggest party of the year.\nB: Yes, until next time!\nA: Right!",funFact:"Germanic cousin of English 'feast', German 'Fest'."},
        {type:"teach",trg:"de vrijmarkt",src:"the free market",pos:"noun",gender:"c",phonetic:"duh VRAY-markt",note:"COMPOUND: vrij + markt.\nvrij + markt = free + market.\nAnyone can sell anything. Kids sell old toys.\nAdults sell second-hand clothes. No rules!",example:"A: Op de vrijmarkt kun je alles kopen.\nB: Is dat niet te duur?\nA: Dat is zo.",exampleSrc:"A: At the free market you can buy everything.\nB: Isn't that too expensive?\nA: That's true.",funFact:"Dutch compounds are transparent once you learn the parts."},
        {type:"mc",q:"Koningsdag is on:",opts:["April 27","December 25","January 1","October 31"],ans:"April 27",hint:"The King's birthday"},
        {type:"fb",opts:["oranje","rood","blauw","zwart"],hint:"The national color!",s:"Iedereen draagt ___ op Koningsdag.",a:"oranje"},
        {type:"match",pairs:[{trg:"de koning",src:"the king"},{trg:"vieren",src:"to celebrate"},{trg:"het feest",src:"the party"},{trg:"de vrijmarkt",src:"the free market"}]},
        {type:"mc",q:"The color orange comes from:",opts:["The Dutch flag","The House of Orange-Nassau","A popular orange drink","Dutch tulips"],ans:"The House of Orange-Nassau",hint:"William of ___, the founding father"},
        {type:"drag_fill",hint:"We're GOING TO celebrate! The biggest PARTY.",s:"Wij {1} Koningsdag vieren! Het is het grootste {2} van het jaar.",blanks:{"1":"gaan","2":"feest"},pool:["gaan","feest","ga","feesten"]},
        {type:"fb",opts:["vrijmarkt","markt","winkel","borrel"],hint:"The FREE market",s:"Op de ___ kun je alles kopen en verkopen.",a:"vrijmarkt"},
        {type:"mc",q:"'Lang leve de Koning!' means:",opts:["The king is tall","The king is leaving","Long live the King!","Long day for the king"],ans:"Long live the King!",hint:"The national cheer"}
  ]},
  {id:"v2u9l8",title:"Unit 9 Review",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Unit 9: Alles Samen",desc:"Future with gaan and zullen. Subordinate clauses with omdat/dat/als. Purpose clauses with om...te. Hobbies, weather, and Koningsdag. All of Unit 9 mixed together.",goals:["gaan + infinitive for plans","zullen for offers and promises","Subordinate clause word order","om...te for purpose","Weather and celebration vocabulary"]},
        {type:"tip",title:"📋 What You Know Now",text:"After Unit 9 you can:\n\n• Talk about hobbies with graag/liever/het liefst\n• Make future plans with gaan + infinitive\n• Make offers with 'Zal ik...?'\n• Give reasons with omdat (verb at end!)\n• Set conditions with als (verb at end!)\n• Express purpose with om...te\n• Talk about weather\n• Celebrate Koningsdag\n\nYou've mastered the hardest word-order rule in Dutch.\nThat's a huge achievement."},
        {type:"mc",q:"'Ik ga morgen zwemmen' uses future with:",opts:["gaan + infinitive","zullen","moeten","hebben"],ans:"gaan + infinitive",hint:"Going to = ___"},
        {type:"fb",opts:["Zal","Ga","Moet","Kan"],hint:"Shall I help? (offer)",s:"___ ik je helpen?",a:"Zal"},
        {type:"mc",q:"After 'omdat', the verb goes:",opts:["second","to the end","first","nowhere"],ans:"to the end",hint:"...omdat ik in Amsterdam WOON."},
        {type:"match",pairs:[{trg:"omdat",src:"because"},{trg:"als",src:"if / when"},{trg:"dat",src:"that"},{trg:"om...te",src:"in order to"}]},
        {type:"drag_fill",hint:"Because it RAINS. If the sun SHINES.",s:"Ik blijf thuis omdat het {1}. Als de zon {2}, ga ik fietsen.",blanks:{"1":"regent","2":"schijnt"},pool:["regent","schijnt","regen","zon"]},
        {type:"fb",opts:["om","dat","als","omdat"],hint:"In order to",s:"Ik leer Nederlands ___ in Amsterdam te werken.",a:"om"},
        {type:"mc",q:"'Gaat wel' as an answer to 'Hoe gaat het?' means:",opts:["Excellent!","I'm leaving","Could be better, could be worse","It doesn't go"],ans:"Could be better, could be worse",hint:"The most Dutch answer"},
        {type:"fb",opts:["graag","liever","het liefst","niet"],hint:"I like swimming, but I prefer walking",s:"Ik zwem ___, maar ik wandel liever.",a:"graag"},
        {type:"mc",q:"Koningsdag is on April 27 because:",opts:["It's the first day of spring","Orange tulips bloom in April","The Netherlands was founded that day","It's King Willem-Alexander's birthday"],ans:"It's King Willem-Alexander's birthday",hint:"The ___'s ___!"},
        {type:"drag_fill",hint:"I think THAT he sick IS.",s:"Ik denk {1} hij ziek {2}.",blanks:{"1":"dat","2":"is"},pool:["dat","is","omdat","ben"]},
        {type:"fb",opts:["gaan","ga","zullen","moeten"],hint:"Wij takes the plural infinitive form, not the -t form",s:"Wij ___ volgende week op vakantie.",a:"gaan"},
        {type:"mc",q:"In 'Als het regent, blijf ik thuis'  -  'blijf' comes before 'ik' because:",opts:["The subordinate clause came first → inversion","It's a question","It's imperative","Dutch always does this"],ans:"The subordinate clause came first → inversion",hint:"___ ___ → verb-subject in main"},
        {type:"tr",mk:"u9v2_going_swimming",dir:"produce"},
        {type:"tr",mk:"u9v2_because_fun",dir:"produce"},
        {type:"tr",mk:"u9v2_if_nice_weather",dir:"produce"},
        {type:"mc",q:"Which sentence uses 'om...te' correctly for purpose?",opts:["Ik leer Nederlands omdat Amsterdam te werken.","Ik leer Nederlands om in Amsterdam te werken.","Ik leer Nederlands als Amsterdam te werken.","Ik leer Nederlands dat in Amsterdam te werken."],ans:"Ik leer Nederlands om in Amsterdam te werken.",hint:"Purpose = om... + te + infinitive at end"}
  ]},
  {id:"v2u9l8b",title:"Beroepen",icon:"👨‍⚕️",xp:20,board:true,steps:[
        {type:"intro",title:"Beroepen",desc:"Learn the names of common professions in Dutch. Some professions have different forms for men and women. You will also learn which articles they use.",goals:["Learn 12 common profession names","Understand gendered profession forms (leraar/lerares)","Talk about jobs and careers"]},
        {type:"teach",trg:"de arts / de dokter",src:"the doctor",pos:"noun",gender:"c",phonetic:"duh ARTS / duh DOK-tur",note:"Both are de-words. Arts = formal. Dokter = informal.\nDe huisarts = GP (house doctor).\nNo gender difference: zij is arts / hij is arts.",example:"A: Wat doet je vader?\nB: Hij is arts.\nA: In het ziekenhuis?\nB: Ja, hij werkt op de spoedeisende hulp.",exampleSrc:"A: What does your father do?\nB: He is a doctor.\nA: At the hospital?\nB: Yes, he works in the emergency room.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de leraar / de lerares",src:"the teacher (m/f)",pos:"noun",gender:"c",phonetic:"duh luh-RAHR / duh luh-rah-RES",note:"Leraar = male teacher. Lerares = female teacher.\n-aar/-ares is a common Dutch gender suffix.\nLesgeven = to teach (les + geven).",example:"A: Mijn lerares is heel aardig.\nB: Wat geeft ze les?\nA: Nederlands.\nB: Dat is een mooi vak!",exampleSrc:"A: My teacher is very nice.\nB: What does she teach?\nA: Dutch.\nB: That is a nice subject!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de verpleegkundige",src:"the nurse",pos:"noun",gender:"c",phonetic:"duh fur-PLAYG-kun-duh-guh",note:"De-word. Same form for male and female.\nOlder term: de verpleger (m) / de verpleegster (f).\nThe modern term is gender-neutral.",example:"A: De verpleegkundige meet mijn bloeddruk.\nB: Is alles goed?\nA: Ja, alles is normaal.\nB: Mooi zo!",exampleSrc:"A: The nurse measures my blood pressure.\nB: Is everything okay?\nA: Yes, everything is normal.\nB: Good!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de politieagent",src:"the police officer",pos:"noun",gender:"c",phonetic:"duh poh-LEE-tsee-ah-GHENT",note:"De-word. Politie (police) + agent.\nDe politie = the police (organization).",example:"A: Er staat een politieagent op de hoek.\nB: Wat is er gebeurd?\nA: Misschien een ongeluk.\nB: Laten we voorzichtig zijn.",exampleSrc:"A: There is a police officer on the corner.\nB: What happened?\nA: Maybe an accident.\nB: Let's be careful.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de brandweerman",src:"the firefighter",pos:"noun",gender:"c",phonetic:"duh BRAHNT-wehr-mahn",note:"De-word. Brand (fire) + weer (defense) + man.\nFemale: de brandweervrouw.\nDe brandweer = the fire department.",example:"A: De brandweerman redt de kat.\nB: Uit een boom?\nA: Ja, hij is heel dapper.\nB: Wat een held!",exampleSrc:"A: The firefighter rescues the cat.\nB: From a tree?\nA: Yes, he is very brave.\nB: What a hero!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de kok",src:"the chef / the cook",pos:"noun",gender:"c",phonetic:"duh KOK",note:"De-word. Cognate with English 'cook'.\nDe chefkok = the head chef.",example:"A: De kok maakt heerlijk eten.\nB: Wat is zijn specialiteit?\nA: Nederlandse stamppot!\nB: Lekker!",exampleSrc:"A: The chef makes delicious food.\nB: What is his specialty?\nA: Dutch stamppot!\nB: Delicious!",funFact:"Germanic cousin of English 'cook', German 'der Koch'."},
        {type:"teach",trg:"de ingenieur",src:"the engineer",pos:"noun",gender:"c",phonetic:"duh in-zhuh-NUHR",note:"De-word. Same form for male and female.\nCognate with English 'engineer'.",example:"A: Zij is ingenieur bij Philips.\nB: Wat voor ingenieur?\nA: Elektrotechnisch.\nB: Dat klinkt interessant!",exampleSrc:"A: She is an engineer at Philips.\nB: What kind of engineer?\nA: Electrical.\nB: That sounds interesting!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de advocaat",src:"the lawyer",pos:"noun",gender:"c",phonetic:"duh aht-voh-KAHT",note:"De-word. Also means 'advocaat' (egg liqueur).\nContext makes it clear which meaning.\nCognate with English 'advocate'.",example:"A: Ik heb een advocaat nodig.\nB: Waarvoor?\nA: Een contract.\nB: Ik ken een goede advocaat.",exampleSrc:"A: I need a lawyer.\nB: For what?\nA: A contract.\nB: I know a good lawyer.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de chauffeur",src:"the driver",pos:"noun",gender:"c",phonetic:"duh shoh-FUHR",note:"De-word. From French, same spelling.\nBuschauffeur = bus driver.\nTaxichauffeur = taxi driver.",example:"A: De chauffeur rijdt heel voorzichtig.\nB: Gelukkig maar!\nA: Ja, veiligheid is belangrijk.\nB: Zeker weten.",exampleSrc:"A: The driver drives very carefully.\nB: Good thing!\nA: Yes, safety is important.\nB: Absolutely.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de zanger / de zangeres",src:"the singer (m/f)",pos:"noun",gender:"c",phonetic:"duh ZAHNG-ur / duh zahng-uh-RES",note:"Zanger = male. Zangeres = female.\n-er/-eres is a common gender suffix.\nZingen = to sing.",example:"A: Zij is een beroemde zangeres.\nB: Welk genre zingt ze?\nA: Pop en jazz.\nB: Ik wil haar concert zien!",exampleSrc:"A: She is a famous singer.\nB: What genre does she sing?\nA: Pop and jazz.\nB: I want to see her concert!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de apotheker",src:"the pharmacist",pos:"noun",gender:"c",phonetic:"duh ah-poh-TAY-kur",note:"De-word. Apotheek (pharmacy) + -er suffix.\nSame form for male and female in modern Dutch.",example:"A: De apotheker geeft me medicijnen.\nB: Heb je een recept?\nA: Ja, van de huisarts.\nB: Dan is het snel klaar.",exampleSrc:"A: The pharmacist gives me medicine.\nB: Do you have a prescription?\nA: Yes, from the GP.\nB: Then it will be ready quickly.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"tip",title:"Gendered Profession Suffixes",text:"Many Dutch professions have gendered forms:\n\nMale suffix -er/-aar, female suffix -ster/-eres:\nleraar / lerares (teacher)\nzanger / zangeres (singer)\nverpleger / verpleegster (nurse, older form)\n\nModern trend: gender-neutral forms:\nde verpleegkundige (nurse)\nde arts (doctor)\nde ingenieur (engineer)\n\nTo ask about professions:\nWat doe je? = What do you do? (informal)\nWat is uw beroep? = What is your profession? (formal)"},
        {type:"mc",q:"What is the female form of 'leraar'?",opts:["lerares","leraarin","lerarster","leraresse"],ans:"lerares",hint:"The -aar ending becomes -ares for the female form."},
        {type:"mc",q:"'De advocaat' can also refer to:",opts:["a type of cheese","a type of Dutch egg liqueur","a court building","a police car"],ans:"a type of Dutch egg liqueur",hint:"This word has two very different meanings in ___."},
        {type:"fb",opts:["verpleegkundige","arts","lerares","apotheker"],hint:"The modern gender-neutral word for a nurse.",s:"Mijn moeder is ___ in het ziekenhuis.\n(My mother is a nurse at the hospital.)",a:"verpleegkundige"},
        {type:"mc",q:"Which profession word is the same for men and women?",opts:["de zanger","de leraar","de ingenieur","de brandweerman"],ans:"de ingenieur",hint:"No separate male/female forms. Modern Dutch trend."},
        {type:"fb",opts:["kok","arts","chauffeur","ingenieur"],hint:"Cognate with English 'cook'. Works in a kitchen.",s:"De ___ maakt heerlijk eten in het restaurant.\n(The chef makes delicious food in the restaurant.)",a:"kok"},
        {type:"match",pairs:[{trg:"de arts",src:"the doctor"},{trg:"de kok",src:"the chef"},{trg:"de chauffeur",src:"the driver"},{trg:"de advocaat",src:"the lawyer"},{trg:"de apotheker",src:"the pharmacist"}]},
        {type:"drag_fill",hint:"The teacher teaches and the nurse works in the hospital.",s:"De {1} geeft les en de {2} werkt in het ziekenhuis.",blanks:{"1":"leraar","2":"verpleegkundige"},pool:["leraar","verpleegkundige","chauffeur","kok"]},
        {type:"mc",q:"How do you ask 'What do you do?' informally in Dutch?",opts:["Hoe heet je?","Wat is uw beroep?","Waar werk je?","Wat doe je?"],ans:"Wat doe je?",hint:"Informal question about someone's job. Short and direct."}
  ]},
  {id:"v2u9l8c",title:"Vervoer",icon:"🚌",xp:20,board:true,steps:[
        {type:"intro",title:"Vervoer",desc:"The Netherlands has excellent public transport. Learn the vocabulary for buses, trains, bikes, and more. You will also learn useful travel expressions.",goals:["Learn 12 transport and travel words","Use travel expressions for getting around","Navigate Dutch public transport vocabulary"]},
        {type:"teach",trg:"de bus",src:"the bus",pos:"noun",gender:"c",phonetic:"duh BUS",note:"De-word. De bus nemen = to take the bus.\nDe bushalte = the bus stop.\nDe buslijn = the bus line/route.",example:"A: Neem jij de bus?\nB: Ja, lijn 12.\nA: Hoe laat vertrekt hij?\nB: Over vijf minuten.",exampleSrc:"A: Are you taking the bus?\nB: Yes, line 12.\nA: What time does it leave?\nB: In five minutes.",funFact:"Germanic cousin of English 'bus', German 'der Bus'."},
        {type:"teach",trg:"de metro",src:"the subway / metro",pos:"noun",gender:"c",phonetic:"duh MAY-troh",note:"De-word. Only Amsterdam and Rotterdam have metros.\nMost Dutch cities use bus and tram.",example:"A: Is er een metro in Amsterdam?\nB: Ja, maar klein.\nA: En in Rotterdam?\nB: Daar ook. De Erasmuslijn is mooi.",exampleSrc:"A: Is there a metro in Amsterdam?\nB: Yes, but small.\nA: And in Rotterdam?\nB: There too. The Erasmus line is nice.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de trein",src:"the train",pos:"noun",gender:"c",phonetic:"duh TRINE",note:"De-word. De NS (Nederlandse Spoorwegen) runs trains.\nHet spoor = the platform/track.\nDe intercity = fast train between cities.",example:"A: Ik neem de trein naar Utrecht.\nB: Welk spoor?\nA: Spoor 3.\nB: Die vertrekt over tien minuten.",exampleSrc:"A: I am taking the train to Utrecht.\nB: Which platform?\nA: Platform 3.\nB: That one leaves in ten minutes.",funFact:"Germanic cousin of English 'train', German 'der Zug (different root)'."},
        {type:"teach",trg:"het vliegtuig",src:"the airplane",pos:"noun",gender:"n",phonetic:"hut FLEEG-towg",note:"COMPOUND: vlieg (fly) + tuig (equipment).\nHet-word. Vlieg (fly) + tuig (craft).\nSchiphol = Amsterdam's international airport.",example:"A: We gaan met het vliegtuig.\nB: Naar welk land?\nA: Naar Spanje.\nB: Leuk! Vanaf Schiphol?",exampleSrc:"A: We are going by airplane.\nB: To which country?\nA: To Spain.\nB: Nice! From Schiphol?",funFact:"A het-word (neuter). About 1/3 of Dutch nouns use 'het'. No reliable rule, learn it with the word."},
        {type:"teach",trg:"de fiets",src:"the bicycle",pos:"noun",gender:"c",phonetic:"duh FEETS",note:"De-word. THE Dutch transport.\nFietsen = to cycle. De fietser = the cyclist.\nThere are more bikes than people in NL.",example:"A: Ik ga met de fiets.\nB: Is het niet te ver?\nA: Nee, maar tien minuten.\nB: In Nederland fietst iedereen!",exampleSrc:"A: I'm going by bicycle.\nB: Isn't it too far?\nA: No, just ten minutes.\nB: In the Netherlands everyone cycles!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de boot",src:"the boat",pos:"noun",gender:"c",phonetic:"duh BOHT",note:"De-word. Cognate with English 'boat'.\nDe veerboot = the ferry.\nDe rondvaartboot = canal tour boat.",example:"A: Zullen we een boot nemen?\nB: Ja, over de gracht!\nA: Dat is heel gezellig.\nB: Neem een warme jas mee.",exampleSrc:"A: Shall we take a boat?\nB: Yes, over the canal!\nA: That is very cozy.\nB: Bring a warm jacket.",funFact:"Germanic cousin of English 'boat', German 'das Boot'."},
        {type:"teach",trg:"het station",src:"the station",pos:"noun",gender:"n",phonetic:"hut stah-SHON",note:"Het-word. Het treinstation = train station.\nHet busstation = bus station.\nAmsterdam Centraal = Amsterdam's main station.",example:"A: Hoe kom ik bij het station?\nB: Rechtdoor en dan links.\nA: Is het ver?\nB: Vijf minuten lopen.",exampleSrc:"A: How do I get to the station?\nB: Straight ahead and then left.\nA: Is it far?\nB: Five minutes walking.",funFact:"Close cousin of English 'the station'. Both languages inherited this from their shared Germanic roots."},
        {type:"teach",trg:"de halte",src:"the stop (bus/tram)",pos:"noun",gender:"c",phonetic:"duh HAHL-tuh",note:"De-word. De bushalte = bus stop.\nDe tramhalte = tram stop.\nUitstappen = to get off.",example:"A: Welke halte moet ik uitstappen?\nB: De derde halte.\nA: Dankjewel!\nB: Geen probleem.",exampleSrc:"A: At which stop do I get off?\nB: The third stop.\nA: Thank you!\nB: No problem.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de luchthaven",src:"the airport",pos:"noun",gender:"c",phonetic:"duh LUKHT-hah-vun",note:"De-word. Lucht (air) + haven (harbor) = air harbor.\nSchiphol is de grootste luchthaven van Nederland.",example:"A: We moeten naar de luchthaven.\nB: Schiphol?\nA: Ja, onze vlucht is om acht uur.\nB: Dan moeten we nu vertrekken!",exampleSrc:"A: We need to go to the airport.\nB: Schiphol?\nA: Yes, our flight is at eight.\nB: Then we need to leave now!",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"het kaartje",src:"the ticket",pos:"noun",gender:"n",phonetic:"hut KAHR-tyuh",note:"Het-word. Diminutive of kaart (card/map).\nEen enkeltje = a single (one-way).\nEen retourtje = a return ticket.",example:"A: Heb je een kaartje gekocht?\nB: Ja, een retourtje.\nA: Naar Den Haag?\nB: Ja, eerste klas.",exampleSrc:"A: Did you buy a ticket?\nB: Yes, a return ticket.\nA: To The Hague?\nB: Yes, first class.",funFact:"A het-word (neuter). About 1/3 of Dutch nouns use 'het'. No reliable rule, learn it with the word."},
        {type:"teach",trg:"overstappen",src:"to transfer / to change",pos:"verb",gender:null,phonetic:"OH-vur-stah-pun",note:"COMPOUND: over (over) + stappen (step).\nSeparable verb: Ik stap over in Utrecht.\nOver (over) + stappen (to step).\nVery common in Dutch train travel.",example:"A: Moet ik overstappen?\nB: Ja, in Utrecht.\nA: Op welk spoor?\nB: Spoor 5, richting Amsterdam.",exampleSrc:"A: Do I have to transfer?\nB: Yes, in Utrecht.\nA: On which platform?\nB: Platform 5, direction Amsterdam.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"tip",title:"Dutch Travel Expressions",text:"Essential travel phrases:\n\nHoe kom ik bij...? = How do I get to...?\nIk wil een kaartje naar... = I want a ticket to...\nEnkeltje of retour? = Single or return?\nOp welk spoor? = On which platform?\nMoet ik overstappen? = Do I have to transfer?\nDe trein heeft vertraging. = The train is delayed.\n\nThe OV-chipkaart is the Dutch public transport card.\nYou check in (inchecken) and check out (uitchecken)."},
        {type:"mc",q:"'De fiets' is the most common transport in the Netherlands because:",opts:["the country is flat and distances are short","cars are forbidden","there are no trains","buses are too expensive"],ans:"the country is flat and distances are short",hint:"The Netherlands is very ___. Perfect for cycling."},
        {type:"mc",q:"'Een retourtje' means:",opts:["a single ticket","a return ticket","a platform number","a bus stop"],ans:"a return ticket",hint:"Retour = r.... The -tje makes it a diminutive noun."},
        {type:"fb",opts:["overstappen","uitstappen","instappen","vertrekken"],hint:"To change from one train to another. Over + stappen.",s:"Ik moet ___ in Utrecht.\n(I have to transfer in Utrecht.)",a:"overstappen"},
        {type:"mc",q:"'Het vliegtuig' is literally:",opts:["the air car","the sky machine","the fly-craft","the wing thing"],ans:"the fly-craft",hint:"Vlieg (___) + tuig (___/device). A device that flies."},
        {type:"fb",opts:["station","halte","vliegtuig","kaartje"],hint:"The place where trains arrive and depart. Het-word.",s:"Hoe kom ik bij het ___?\n(How do I get there?)",a:"station"},
        {type:"match",pairs:[{trg:"de trein",src:"the train"},{trg:"de fiets",src:"the bicycle"},{trg:"het vliegtuig",src:"the airplane"},{trg:"de boot",src:"the boat"},{trg:"de halte",src:"the stop"}]},
        {type:"drag_fill",hint:"I take the train to the station and then the airplane to Spain.",s:"Ik neem de {1} naar het {2} en dan het {3} naar Spanje.",blanks:{"1":"trein","2":"station","3":"vliegtuig"},pool:["trein","station","vliegtuig","fiets"]}
  ,{type:"match",pairs:[{trg:"het bos",src:"the forest"},{trg:"denken",src:"to think"},{trg:"weten",src:"to know (a fact)"},{trg:"dus",src:"so / therefore"},{trg:"de arts / de dokter",src:"the doctor"},{trg:"de politieagent",src:"the police officer"}]},{type:"match",pairs:[{trg:"de metro",src:"the subway / metro"},{trg:"de luchthaven",src:"the airport"},{trg:"het kaartje",src:"the ticket"}]}]},
  {id:"v2u9l9",title:"Buiten: Park, Strand & Meer",icon:"🏖️",xp:15,board:true,steps:[
        {type:"intro",title:"Buiten: Park, Strand & Meer",desc:"Dutch leisure often happens outdoors. Learn the essential outdoor places and how to describe situations.",goals:["het park: park","het strand: beach","het zwembad: swimming pool","de situatie: situation","Use them in conversation"]},
        {type:"teach",trg:"het park",src:"the park",pos:"noun",gender:"n",phonetic:"hut park",note:"Het-word. Plural: parken.\nThe Netherlands has many beautiful parks.\nGaan naar het park = to go to the park.\nIn het park wandelen = to walk in the park.",example:"A: Ga je mee naar het park?\nB: Ja, graag! Om hoe laat?\nA: Om drie uur.",exampleSrc:"A: Are you coming to the park?\nB: Yes, please! What time?\nA: At three o'clock.",funFact:"Cognate with English 'park', German 'Park'. All from Old French 'parc' (enclosed space)."},
        {type:"teach",trg:"het strand",src:"the beach",pos:"noun",gender:"n",phonetic:"hut strahnt",note:"Het-word. Plural: stranden.\nThe Netherlands has 450 km of coastline.\nZandvoort and Scheveningen are the most popular beaches.\n'Naar het strand gaan' = to go to the beach.",example:"A: Ik ga in de zomer naar het strand.\nB: Leuk! De zon schijnt vandaag.\nA: Dan ga ik nu al!",exampleSrc:"A: I go to the beach in summer.\nB: Nice! The sun is shining today.\nA: Then I'll go right now!",funFact:"Germanic cousin of English 'strand', German 'Strand'. Related to the English word 'stranded' (left on a shore)."},
        {type:"teach",trg:"het zwembad",src:"the swimming pool",pos:"noun",gender:"n",phonetic:"hut ZVEM-baht",note:"COMPOUND: zwem (swim) + bad (bath).\nHet-word. Literally: 'swim-bath'.\nThe Netherlands has many public zwembaden.\n'Binnenzwembad' = indoor pool. 'Buitenzwembad' = outdoor pool.",example:"A: Gaan we naar het zwembad?\nB: Ja! Het is warm vandaag.\nA: Goed plan!",exampleSrc:"A: Shall we go to the swimming pool?\nB: Yes! It is warm today.\nA: Good plan!",funFact:"Compound of 'zwemmen' (to swim) and 'bad' (bath). Dutch makes new words by joining existing ones directly."},
        {type:"teach",trg:"de situatie",src:"the situation",pos:"noun",gender:"c",phonetic:"duh see-too-AH-see",note:"De-word. Plural: situaties.\nUsed in many contexts: personal, social, professional.\n'In deze situatie' = in this situation.\n'De situatie is onduidelijk.' = The situation is unclear.",example:"A: Hoe is de situatie?\nB: Niet makkelijk, maar we lossen het op.\nA: Goed, we werken er samen aan.",exampleSrc:"A: How is the situation?\nB: Not easy, but we will solve it.\nA: Good, we will work on it together.",funFact:"Cognate with English 'situation', French 'situation', German 'Situation'. From Latin 'situatio'."},
        {type:"tip",title:"🏖️ Dutch Summer Leisure",text:"Dutch people love outdoor leisure when the sun appears:\n\nNaar het strand gaan = to go to the beach\nIn het park zitten = to sit in the park\nIn het zwembad zwemmen = to swim in the pool\nIn het bos wandelen = to walk in the forest\n\nThe Dutch expression 'heerlijk buiten' (lovely outside) sums it up.\nWhen the sun shines, everyone goes outside immediately."},
        {type:"mc",q:"'Het zwembad' is a compound of:",opts:["swim + bad (bath)","swim + bad (bad)","swim + pad (path)","swim + boat"],ans:"swim + bad (bath)",hint:"Zwem = aquatic exercise. The second part is a container of water you soak in at home."},
        {type:"mc",q:"'Naar het strand gaan' means:",opts:["to go to the forest","to go to the beach","to go to the pool","to go to the park"],ans:"to go to the beach",hint:"Strand = b..."},
        {type:"fb",opts:["situatie","plan","idee","keuze"],hint:"'In deze ___' = 'In this ___' (describing what's happening around you)",s:"De ___ is niet makkelijk.",a:"situatie"},
        {type:"mc",q:"Which word is a compound meaning 'swim-bath'?",opts:["het park","het bos","het zwembad","het strand"],ans:"het zwembad",hint:"Zwem = swim. The second part is the Dutch word for a tub you soak in."},
        {type:"match",pairs:[{trg:"het park",src:"the park"},{trg:"het strand",src:"the beach"},{trg:"het zwembad",src:"the swimming pool"},{trg:"de situatie",src:"the situation"}]},
        {type:"fb",opts:["strand","park","bos","zwembad"],hint:"450 km of coastline: the Dutch love the ___",s:"In de zomer ga ik naar het ___.",a:"strand"}
  ]},
  {id:"v2u9l_mindstate",title:"Hopen, Beslissen & Verwachten",icon:"🧠",xp:20,board:true,steps:[
        {type:"intro",title:"Hopen, Beslissen & Verwachten",desc:"Dutch has specific verbs for internal mental states: hoping, deciding, expecting, preferring, needing. These are tested on NT2 A2 and essential for expressing your thoughts and intentions naturally.",goals:["hopen: to hope","beslissen: to decide","verwachten: to expect","voorkeur geven: to prefer","nodig hebben: to need"]},
        {type:"teach",trg:"hopen",src:"to hope",pos:"verb",gender:null,phonetic:"HOH-pun",note:"Regular verb. Stam = hoop.\n'Ik hoop dat...' = I hope that... (verb-final in that clause).\nVery common in both speech and writing.",example:"A: Ik hoop dat het mooi weer wordt.\nB: Ik ook! Dan gaan we wandelen.\nA: Goed plan!",exampleSrc:"A: I hope the weather will be nice.\nB: Me too! Then we'll go walking.\nA: Good plan!",funFact:"Germanic cousin of English 'hope' and German 'hoffen'. All three go back to the same Proto-Germanic root meaning 'to leap forward with expectation'."},
        {type:"teach",trg:"beslissen",src:"to decide",pos:"verb",gender:null,phonetic:"buh-SLIS-sun",note:"Regular verb. Stam = beslis.\nPP: beslist (no ge-! be- prefix blocks it).\n'Ik heb besloten' = I have decided (besluiten is the synonym, more literary).",example:"A: Heb je al besloten waar je naartoe gaat?\nB: Ik ga naar het strand.\nA: Goed besloten!",exampleSrc:"A: Have you decided where you're going?\nB: I'm going to the beach.\nA: Good decision!",funFact:"The be- prefix in Dutch verbs always blocks the ge- in past participle. This same rule applies to betalen, beslissen, beginnen, and begrijpen."},
        {type:"teach",trg:"verwachten",src:"to expect",pos:"verb",gender:null,phonetic:"fur-WAKH-tun",note:"Regular verb. Stam = verwacht.\nPP: verwacht (ver- prefix blocks ge-).\n'Ik verwacht dat...' = I expect that... (verb-final).\nAlso used for awaiting / anticipating.",example:"A: Ik verwacht dat hij morgen komt.\nB: Weet je het zeker?\nA: Ja, hij heeft het beloofd.",exampleSrc:"A: I expect that he will come tomorrow.\nB: Are you sure?\nA: Yes, he promised.",funFact:"The ver- prefix appears in many Dutch verbs: vergeten, verlagen, veranderen. It often adds a sense of change or completion."},
        {type:"teach",trg:"voorkeur geven",src:"to prefer / to give preference",pos:"verb",gender:null,phonetic:"VOHR-kuhr GAY-vun",note:"IDIOM: voorkeur (preference) + geven (to give).\n'Ik geef de voorkeur aan...' = I prefer...\n'Voorkeur' = de-word. Geven is the main verb.",example:"A: Geef jij de voorkeur aan koffie of thee?\nB: Ik geef de voorkeur aan koffie.\nA: Ik ook!",exampleSrc:"A: Do you prefer coffee or tea?\nB: I prefer coffee.\nA: Me too!",funFact:"'Voorkeur geven' is the formal register. Informally, Dutch speakers often say 'liever hebben': 'Ik heb liever koffie.' Both mean the same thing."},
        {type:"teach",trg:"nodig hebben",src:"to need",pos:"verb",gender:null,phonetic:"NOH-dug HEB-bun",note:"IDIOM: nodig (necessary) + hebben (to have).\n'Ik heb X nodig.' = I need X.\n'Nodig' goes to the END of the clause.\n'Heb' conjugates as usual.",example:"A: Ik heb een pen nodig.\nB: Hier is er een.\nA: Dank je, dat was nodig!",exampleSrc:"A: I need a pen.\nB: Here is one.\nA: Thank you, I really needed that!",funFact:"'Nodig hebben' follows the same end-position pattern as separable verbs. 'Nodig' is technically an adjective used predicatively, not a particle, but it behaves like one."},
        {type:"tip",title:"Mental State Verbs in Subordinate Clauses",text:"All five verbs in this lesson combine with subordinate clauses:\n\nhopen dat + [verb at end]:\nIk hoop dat hij komt. = I hope he comes.\n\nbeslissen om... te...:\nIk heb besloten om te gaan. = I decided to go.\n\nverwachten dat + [verb at end]:\nIk verwacht dat het regent. = I expect it will rain.\n\nvoorkeur geven aan + noun:\nIk geef de voorkeur aan thee. = I prefer tea.\n\nnodig hebben (nodig at end):\nIk heb meer tijd nodig. = I need more time.\n\nThe verb-final and om...te rules from this unit apply directly here."},
        {type:"mc",q:"'Ik hoop dat het regent' has 'regent' at the end because:",opts:["'dat' triggers verb-final order","'hopen' is irregular","It's a question","Dutch always puts verbs last"],ans:"'dat' triggers verb-final order",hint:"Subordinating conjunctions like 'dat' send the finite word to the clause boundary"},
        {type:"fb",opts:["hoop","hopen","hoopt","gehoopt"],hint:"I HOPE (ik = stem, no -t)",s:"Ik ___ dat het morgen beter wordt.",a:"hoop"},
        {type:"mc",q:"'Ik heb besloten om te gaan.' The past participle of 'beslissen' is:",opts:["besloten","beslist","beslissend","gebesloten"],ans:"beslist",hint:"The be- prefix always blocks ge- from attaching. Stam = beslis, so: be- + stam + -t"},
        {type:"fb",opts:["verwacht","verwachten","hoop","beslis"],hint:"I EXPECT that he is coming (ver- verb, stam-form for 'ik')",s:"Ik ___ dat hij morgen komt.",a:"verwacht"},
        {type:"match",pairs:[{trg:"hopen",src:"to hope"},{trg:"beslissen",src:"to decide"},{trg:"verwachten",src:"to expect"},{trg:"voorkeur geven",src:"to prefer"},{trg:"nodig hebben",src:"to need"}]},
        {type:"fb",opts:["voorkeur","liever","graag","koffie"],hint:"I give the ___FERENCE to coffee (the Dutch noun for preference)",s:"Ik geef de ___ aan koffie.",a:"voorkeur"},
        {type:"drag_fill",hint:"I need a pen. She expects that he is coming.",s:"Ik heb een pen {1}. Zij {2} dat hij komt.",blanks:{"1":"nodig","2":"verwacht"},pool:["nodig","verwacht","beslissen","hopen"]},
        {type:"fb",opts:["nodig","graag","liever","goed"],hint:"Place the adjective at the clause boundary to express the need",s:"Ik heb meer tijd ___.",a:"nodig"},
        {type:"mc",q:"Which sentence uses 'nodig hebben' correctly?",opts:["Ik nodig heb een pen.","Ik heb nodig een pen.","Ik heb een pen nodig.","Nodig ik een pen heb."],ans:"Ik heb een pen nodig.",hint:"The adjective always follows the object, at the clause boundary"},
        {type:"fb",opts:["besloten","beslist","gebesloten","beslissen"],hint:"Past participle of beslissen (be- blocks ge-, stam = beslis)",s:"Ik heb ___ om morgen te gaan.",a:"beslist"},
        {type:"mc",q:"'Voorkeur geven' in formal Dutch means the same as:",opts:["verwachten","graag doen","nodig hebben","liever hebben (informal)"],ans:"liever hebben (informal)",hint:"Both mean to prefer. One is formal, one is everyday."},
        {type:"drag_fill",hint:"I hope the weather is nice. I prefer walking.",s:"Ik {1} dat het mooi weer {2}. Ik geef de voorkeur aan wandelen.",blanks:{"1":"hoop","2":"wordt"},pool:["hoop","wordt","verwacht","beslissen"]}
  ]},
  {id:"v2uNl_letter",title:"Een Kort Briefje",icon:"✉️",xp:15,board:true,steps:[
        {type:"intro",title:"Writing Short Informal Letters",desc:"Learn the conventions for writing short informal letters and emails in Dutch: how to open, what body phrases to use, and how to close. These are tested on NT2 A2 and are essential for everyday Dutch correspondence.",goals:["Open a letter informally","Use common body phrases","Close with an appropriate farewell"]},
        {type:"teach",trg:"Hoi, [naam]!",src:"Hi, [name]! (informal letter/message opening)",pos:"intj",gender:null,note:"The most casual way to open a letter, text, or email to a friend.\n'Hoi' = hi. Follow with the person's first name.\nAlternative: 'Hey, [naam]!'",example:"A: Hoi, Emma! Hoe is het met jou?\nB: Goed, dank je! En met jou?\nA: Prima!",exampleSrc:"A: Hi, Emma! How are you doing?\nB: Good, thanks! And you?\nA: Great!",funFact:"'Hoi' entered Dutch from English 'hi' in the 20th century and is now more common than 'hallo' among friends."},
        {type:"teach",trg:"Beste [naam],",src:"Dear [name], (semi-informal letter opening)",pos:"intj",gender:null,note:"'Beste' = dear (literally: best/dearest).\nUse for friends, classmates, or colleagues you know by first name.\nMore polite than 'Hoi' but not stiff or formal.\nUnit 2 taught 'Beste meneer/mevrouw' for strangers, this is the friendly version.",example:"A: Beste Sofie, hoe gaat het met jou?\nB: Goed, dank je! En met jou?\nA: Ook goed!",exampleSrc:"A: Dear Sofie, how are you doing?\nB: Good, thanks! And you?\nA: Also good!",funFact:"'Beste' as a salutation is used all over the Dutch-speaking world, from Amsterdam to Antwerp."},
        {type:"teach",trg:"Hoe gaat het met jou?",src:"How are you doing? (in writing)",pos:"intj",gender:null,note:"The standard body opener in a Dutch letter or email.\n'Met jou' (with you) emphasises it is about the reader.\nIn speech: 'Hoe gaat het?' works too.\nIn writing, 'met jou' feels more personal and warm.",example:"A: Hoe gaat het met jou?\nB: Prima, dank je!\nA: Goed zo!",exampleSrc:"A: How are you doing?\nB: Great, thanks!\nA: Good!",funFact:"Dutch letter conventions were codified in the 17th century, the Golden Age of Dutch trade, when clear written communication was a commercial necessity."},
        {type:"teach",trg:"Ik schrijf je om...",src:"I'm writing to you to... (purpose opener)",pos:"verb",gender:null,note:"'Schrijven' = to write. 'Je' = you (informal).\nCombines 'om...te' (Unit 9, lesson 6) in a real writing context.\nUse to state the reason for your letter: 'Ik schrijf je om plannen te maken.'",example:"A: Ik schrijf je om plannen te maken.\nB: Leuk! Wat wil je doen?\nA: Ik wil dit weekend naar het strand.",exampleSrc:"A: I'm writing to you to make plans.\nB: Great! What do you want to do?\nA: I want to go to the beach this weekend.",funFact:"The 'om...te' construction you learned in Unit 9 is especially common in informal writing, where tone is friendly but sentences are still complete."},
        {type:"teach",trg:"liefs,",src:"love, / with love, (informal closing)",pos:"intj",gender:null,note:"Very warm, affectionate closing.\nUsed between close friends, family, or romantic partners.\n'Liefs' is short for 'met liefs' (with love).\nAlso common: 'Veel liefs,' = Lots of love.",example:"A: Liefs, Anna\nB: Dat is zo goed!\nA: Dank je, ik schrijf je graag.",exampleSrc:"A: Love, Anna\nB: That is so nice!\nA: Thank you, I love writing to you.",funFact:"'Liefs' as a closing is so standard in Dutch that it is used even between friends who are not romantically involved, it simply means warmth and closeness."},
        {type:"teach",trg:"groetjes,",src:"regards, / lots of love, (informal closing)",pos:"intj",gender:null,note:"A very common informal closing, slightly less warm than 'liefs'.\n'Groetjes' is the diminutive plural of 'groet' (greeting).\nShortened to 'Gr,' in text messages.\nUse between friends or friendly colleagues.",example:"A: Groetjes, Tom\nB: Goed!\nA: Ik schrijf je snel.",exampleSrc:"A: Regards, Tom\nB: Great!\nA: I'll write to you soon.",funFact:"The diminutive -je in 'groetjes' makes the word sound warmer and more affectionate, a very Dutch way to soften language."},
        {type:"teach",trg:"Tot snel!",src:"See you soon! / Talk soon! (farewell phrase)",pos:"intj",gender:null,note:"'Tot' = until. 'Snel' = soon/quickly.\nLiterally: 'Until soon!'\nUsed at the end of a letter, message, or in conversation.\nVariants: 'Tot later!' (until later), 'Tot dan!' (until then).",example:"A: Tot snel!\nB: Ja, tot snel!\nA: Ik schrijf je snel.",exampleSrc:"A: See you soon!\nB: Yes, see you soon!\nA: I'll write to you soon.",funFact:"'Tot' is a preposition of time and also exists in English as 'till', both come from the same Germanic root. Dutch 'tot snel' maps neatly onto English 'till soon'."},
        {type:"tip",title:"Sample Informal Letter",text:"Here is what a complete short informal Dutch letter looks like:\n\nHoi, Emma!\n\nHoe gaat het met jou?\nIk schrijf je om plannen te maken.\nWil je dit weekend naar het strand?\nHet wordt mooi weer.\n\nGroetjes,\nSofie\n\nStructure:\n1. Opening: Hoi, [naam]! OR Beste [naam],\n2. Body opener: Hoe gaat het met jou?\n3. Purpose: Ik schrijf je om...\n4. Closing: Groetjes, / Liefs,\n5. Name\n\nThis five-part format is standard for NT2 A2 writing tasks."},
        {type:"mc",q:"Which opening is most casual for a friend's letter?",opts:["Hoi, Emma!","Met vriendelijke groet,","Beste meneer Jansen,","Geachte mevrouw,"],ans:"Hoi, Emma!",hint:"The most informal Dutch letter opener, same as a text message"},
        {type:"fb",opts:["Hoi","Geachte","Hoogachtend","Dag"],hint:"The most casual Dutch letter greeting, like a text message",s:"___, Anna! Hoe gaat het met jou?",a:"Hoi"},
        {type:"fb",opts:["Beste","Geachte","Hoi","Hoogachtend"],hint:"Friendly but more polite than 'Hoi', used with first name, not surname",s:"___ Lars, hoe gaat het met jou?",a:"Beste"},
        {type:"fb",opts:["groetjes","Hoogachtend","Met vriendelijke groet","Geachte"],hint:"A warm informal letter closing, diminutive plural of 'groet'",s:"___,\nSofie",a:"groetjes"},
        {type:"fb",opts:["Liefs","Hoogachtend","Met vriendelijke groet","Geachte"],hint:"The warmest informal closing, from the word for love, used between close friends",s:"___,\nAnna",a:"Liefs"},
        {type:"fb",opts:["schrijf","stuur","lees","bel"],hint:"'Ik ___ je om plannen te maken', what do you do with a letter?",s:"Ik ___ je om plannen te maken.",a:"schrijf"},
        {type:"fb",opts:["Tot snel!","Tot nooit!","Dag!","Groetjes!"],hint:"'Until soon!', use this to say you will be in touch again soon",s:"Liefs,\nSofie\n\n___ (see you soon!)",a:"Tot snel!"},
        {type:"drag_fill",hint:"Fill in the greeting and the body opener of an informal note.",s:"{1}, Lars!\n\n{2} gaat het met jou?\n\nLiefs,\nMia",blanks:{"1":"Hoi","2":"Hoe"},pool:["Hoi","Hoe","Geachte","Welke"]}
  ]}
]};
